var e=[{id:`L4_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NEXT_NULL`,text:{KOREA:`…예전에 레이 선배가 말했지? `,JPN:`……前にレイ先輩は言ったよね？ `,ENG:`...You told me before.`,TWN:`……以前雷伊前輩說過吧？`},stage:{bg:`THRONE_VOID`,slots:{L:null,C:{char_id:`YOOMINA_FENRIR_NEXT_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L5_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NEXT_NULL`,text:{KOREA:`때로는 진실을 모르는 채로 남아 있는 편이 낫다고.`,JPN:`時には真実を知らないままの方がいいこともあるって。`,ENG:`That sometimes I'll be happier not knowing things.`,TWN:`有時候不知道真相反而更好。`},stage:{bg:`THRONE_VOID`,slots:{L:null,C:{char_id:`YOOMINA_FENRIR_NEXT_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NEXT_NULL`,text:{KOREA:`그래도 나는 확인해야겠어.`,JPN:`それでも私は知りたい。`,ENG:`But I still need to know.`,TWN:`但我還是想要知道，想要去了解。`},stage:{bg:`THRONE_VOID`,slots:{L:null,C:{char_id:`YOOMINA_FENRIR_NEXT_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L7_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NEXT_NULL`,text:{KOREA:`선배 말처럼 괴로울 수도 있겠지만……!`,JPN:`先輩の言う通り、辛いことかもしれない……！`,ENG:`It might be painful, like you said...!`,TWN:`雖然可能會像前輩說的那樣痛苦……！`},stage:{bg:`THRONE_VOID`,slots:{L:null,C:{char_id:`YOOMINA_FENRIR_NEXT_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L8_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NEXT_NULL`,text:{KOREA:`감당하기 힘들지도 모르지만……!`,JPN:`耐えがたいものかもしれない……！`,ENG:`It might be hard for me to bear...!`,TWN:`或許還很難承受……！`},stage:{bg:`THRONE_VOID`,slots:{L:null,C:{char_id:`YOOMINA_FENRIR_NEXT_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L9_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NEXT_NULL`,text:{KOREA:`아무것도 모르는 채로 사람들을 잃어 버리는 건 지긋지긋하다고!!`,JPN:`でも何も知らないまま人を失うのはもう、うんざりなの！！`,ENG:`But I am sick and tired of losing people without knowing why!`,TWN:`但是我已經厭倦在一無所知的情況下失去誰了！！`},stage:{bg:`THRONE_VOID`,slots:{L:null,C:{char_id:`YOOMINA_FENRIR_NEXT_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`SAVIOR_KNIGHT_NULL_NULL`,text:{KOREA:` ……그게 운명이란 겁니다!`,JPN:` ……それが運命なんです！`,ENG:`...That's how fate works!`,TWN:`……這就是命運！`},stage:{bg:`THRONE_VOID`,slots:{L:null,C:{char_id:`SAVIOR_KNIGHT_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`SAVIOR_KNIGHT_NULL_NULL`,text:{KOREA:` 전하도 알렌도, 루크레시아도, 샬롯도!`,JPN:` 殿下もアレンも、ルクレシアも、シャーロットも！`,ENG:`His Highness, Allen, Lucrecia, and Carlota!`,TWN:`殿下，艾倫，露可蕾西亞和夏洛特！`},stage:{bg:`THRONE_VOID`,slots:{L:null,C:{char_id:`SAVIOR_KNIGHT_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`SAVIOR_KNIGHT_NULL_NULL`,text:{KOREA:` 좋아서 떠나 보낸 사람은 아무도 없습니다!`,JPN:` 失ってもいい人なんて一人もいなかった！`,ENG:`Not a single person was lost because I wanted them to be!`,TWN:`沒有一個是我願意送走的！`},stage:{bg:`THRONE_VOID`,slots:{L:null,C:{char_id:`SAVIOR_KNIGHT_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NEXT_NULL`,text:{KOREA:`나도 한때는 그렇게 생각했어.`,JPN:`私も前はそう思っていた。`,ENG:`I used to think the same way.`,TWN:`我也曾經那樣想過。`},stage:{bg:`THRONE_VOID`,slots:{L:null,C:{char_id:`YOOMINA_FENRIR_NEXT_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NEXT_NULL`,text:{KOREA:`죽은 친구도.`,JPN:`死んだ友達も。`,ENG:`My dead friend.`,TWN:`死去的朋友。`},stage:{bg:`MAINSTREAM_320010`,slots:{L:null,C:{char_id:`YOOMINA_FENRIR_NEXT_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NEXT_NULL`,text:{KOREA:`쓰러져 버린 언니도.`,JPN:`倒れた姉さんも。`,ENG:`My fallen sister.`,TWN:`病倒的姊姊。`},stage:{bg:`AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_210010`,slots:{L:null,C:{char_id:`YOOMINA_FENRIR_NEXT_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L21_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NEXT_NULL`,text:{KOREA:`망가진 내 인생도…`,JPN:`壊れてしまった私の人生も……`,ENG:`My broken life...`,TWN:`毀掉我的人生……`},stage:{bg:`MAINSTREAM_344010`,slots:{L:null,C:{char_id:`YOOMINA_FENRIR_NEXT_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L22_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NEXT_NULL`,text:{KOREA:`그저 운명일 뿐이라고.`,JPN:`ただの運命だって。`,ENG:`Perhaps it's just fate.`,TWN:`全都是命運。`},stage:{bg:`MAINSTREAM_344010`,slots:{L:null,C:{char_id:`YOOMINA_FENRIR_NEXT_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L23_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NEXT_NULL`,text:{KOREA:`하지만 그 운명에 맞서는 사람들이 있었어.`,JPN:`でもその運命に立ち向かう人たちがいた。`,ENG:`But there were people who were fighting against that.`,TWN:`但是有的人在對抗命運。`},stage:{bg:`MAINSTREAM_344010`,slots:{L:null,C:{char_id:`YOOMINA_FENRIR_NEXT_NULL`,face:`UNIT_HATE`},R:null}}}];export{e as default};